import { AlertCircle, Flag, FolderOpen } from "lucide-react";
import { ProgressDashboard } from "@/components/dashboard/progress-dashboard";
import { useMilestoneData } from "@/hooks/use-milestone-data";
import { useProjectStore } from "@/stores/project-store";
import { LoadingState } from "@/components/shared/loading-state";
import { EmptyState } from "@/components/shared/empty-state";

export function MilestonesPage() {
  const activeProject = useProjectStore((s) => s.activeProject);
  const { milestones, isLoading, error } = useMilestoneData();

  return (
    <div className="flex flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <Flag className="h-6 w-6 text-primary" data-testid="page-icon" />
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">Milestones</h1>
          <p className="text-sm text-muted-foreground">
            Track milestone progress and deliverables.
          </p>
        </div>
      </div>
      {!activeProject ? (
        <EmptyState
          icon={FolderOpen}
          title="No project selected"
          description="Select a project from the gallery to view milestones."
        />
      ) : isLoading ? (
        <LoadingState message="Loading milestone data…" />
      ) : error ? (
        <EmptyState
          icon={AlertCircle}
          title="Failed to load milestones"
          description={error}
        />
      ) : milestones.length === 0 ? (
        <EmptyState
          icon={Flag}
          title="No milestones"
          description="This project has no milestones yet."
        />
      ) : (
        <ProgressDashboard milestones={milestones} />
      )}
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from "react";
import { createGsdClient } from "@/services/gsd-client";
import { useProjectStore } from "@/stores/project-store";
import { deriveCostData } from "@/lib/derive-cost-data";
import type { MilestoneInfo, CostData } from "@/lib/types";

const client = createGsdClient();

interface UseMilestoneDataResult {
  milestones: MilestoneInfo[];
  costData: CostData;
  isLoading: boolean;
  error: string | null;
  refetch: () => void;
}

const emptyCostData: CostData = {
  totalCost: 0,
  budgetCeiling: null,
  byPhase: [],
  byModel: [],
  bySlice: [],
};

/**
 * Hook that fetches parsed milestone data when the active project changes.
 *
 * Subscribes to `useProjectStore.activeProject`. When it changes to a
 * non-null value, calls `parseProjectMilestones` via the GSD client
 * and derives cost data from the result.
 *
 * Returns `{ milestones, costData, isLoading, error, refetch }`.
 */
export function useMilestoneData(): UseMilestoneDataResult {
  const activeProject = useProjectStore((s) => s.activeProject);
  const [milestones, setMilestones] = useState<MilestoneInfo[]>([]);
  const [costData, setCostData] = useState<CostData>(emptyCostData);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Track the fetch generation to discard stale responses
  const fetchGenRef = useRef(0);

  const fetchData = useCallback(
    async (projectPath: string) => {
      const gen = ++fetchGenRef.current;
      setIsLoading(true);
      setError(null);

      try {
        const data = await client.parseProjectMilestones(projectPath);

        // Discard if a newer fetch has been initiated
        if (gen !== fetchGenRef.current) return;

        setMilestones(data);
        setCostData(deriveCostData(data));
      } catch (err) {
        if (gen !== fetchGenRef.current) return;

        const message = err instanceof Error ? err.message : String(err);
        setError(message);
        setMilestones([]);
        setCostData(emptyCostData);
      } finally {
        if (gen === fetchGenRef.current) {
          setIsLoading(false);
        }
      }
    },
    [],
  );

  // Fetch when activeProject changes
  useEffect(() => {
    if (!activeProject) {
      setMilestones([]);
      setCostData(emptyCostData);
      setError(null);
      setIsLoading(false);
      return;
    }

    fetchData(activeProject.path);
  }, [activeProject, fetchData]);

  const refetch = useCallback(() => {
    if (activeProject) {
      fetchData(activeProject.path);
    }
  }, [activeProject, fetchData]);

  return { milestones, costData, isLoading, error, refetch };
}

// ---------------------------------------------------------------------------
// Shared TypeScript types mirroring Rust IPC structs
// This is the single source of truth for all frontend ↔ Tauri boundary types.
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// RPC Commands (frontend → GSD process via stdin)
// Mirrors: src-tauri/src/gsd_rpc.rs — RpcCommand
// serde(tag = "type", rename_all = "snake_case")
// ---------------------------------------------------------------------------

export type RpcCommand =
  | { type: "prompt"; text: string }
  | { type: "steer"; text: string }
  | { type: "abort" }
  | { type: "get_state" }
  | { type: "set_model"; model: string }
  | { type: "get_available_models" }
  | { type: "get_session_stats" }
  | { type: "get_messages" }
  | { type: "new_session" };

// ---------------------------------------------------------------------------
// RPC Events (GSD process → frontend via stdout)
// Mirrors: src-tauri/src/gsd_rpc.rs — RpcEvent
// serde(tag = "type", rename_all = "snake_case")
// Field names stay snake_case in JSON (no rename_all on struct fields).
// ---------------------------------------------------------------------------

export type RpcEvent =
  | { type: "agent_start"; session_id: string }
  | { type: "agent_end"; session_id: string }
  | { type: "assistant_message"; content: string; done: boolean }
  | { type: "tool_execution_start"; tool: string; id: string }
  | { type: "tool_execution_end"; tool: string; id: string; success: boolean }
  | {
      type: "extension_ui_request";
      request_id: string;
      kind: string;
      payload: unknown;
    }
  | { type: "session_state_changed"; payload: unknown }
  | { type: "error"; message: string };

// ---------------------------------------------------------------------------
// Query types
// Mirrors: src-tauri/src/gsd_query.rs
// serde(rename_all = "camelCase")
// ---------------------------------------------------------------------------

/** Snapshot of GSD project state, returned by `query_gsd_state` command. */
export interface QuerySnapshot {
  currentMilestone: string | null;
  activeTasks: number;
  totalCost: number;
}

/** A discovered GSD project directory. */
export interface ProjectInfo {
  id: string;
  name: string;
  path: string;
}

/** A project stored in the persistent registry. */
export interface SavedProject {
  id: string;
  name: string;
  path: string;
  description: string | null;
  addedAt: string;
}

/** Extended project info for gallery display. Built client-side from ProjectInfo + QuerySnapshot. */
export interface ProjectDisplayInfo extends ProjectInfo {
  status: "active" | "paused" | "idle";
  currentMilestone: string | null;
  totalCost: number;
  progress: number; // 0-100
  lastActivity: string | null; // ISO timestamp or null
}

// ---------------------------------------------------------------------------
// Milestone / Slice / Task tree types (for progress dashboard & roadmap)
// ---------------------------------------------------------------------------

export type CompletionStatus = "done" | "in-progress" | "pending" | "blocked";
export type RiskLevel = "low" | "medium" | "high";

export interface TaskInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  cost: number;
  duration: string | null;
}

export interface SliceInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  risk: RiskLevel;
  cost: number;
  progress: number; // 0-100
  tasks: TaskInfo[];
  depends: string[];
}

export interface MilestoneInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  cost: number;
  progress: number; // 0-100
  slices: SliceInfo[];
}

// ---------------------------------------------------------------------------
// Cost data types (for cost overview charts)
// ---------------------------------------------------------------------------

export interface CostByPhase {
  phase: string;
  cost: number;
}

export interface CostByModel {
  model: string;
  cost: number;
}

export interface CostData {
  totalCost: number;
  budgetCeiling: number | null;
  byPhase: CostByPhase[];
  byModel: CostByModel[];
  bySlice: { sliceId: string; title: string; cost: number }[];
}

// ---------------------------------------------------------------------------
// Session types (for session browser)
// ---------------------------------------------------------------------------

export interface SessionInfo {
  id: string;
  name: string;
  messageCount: number;
  cost: number;
  createdAt: string; // ISO
  lastActiveAt: string; // ISO
  preview: string; // first message preview
  parentId: string | null;
  isActive: boolean;
}

// ---------------------------------------------------------------------------
// Process event payloads
// Mirrors: src-tauri/src/gsd_process.rs
// No rename_all — fields are single-word, so no casing issue.
// ---------------------------------------------------------------------------

/** Payload emitted as a `gsd-event` Tauri event for each JSONL line from stdout. */
export interface GsdEventPayload {
  raw: string;
  timestamp: number;
}

/** Payload emitted as `gsd-process-exit`. */
export interface GsdExitPayload {
  code: number | null;
  timestamp: number;
}

/** Payload emitted as `gsd-process-error`. */
export interface GsdErrorPayload {
  message: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// File watcher payload
// Mirrors: src-tauri/src/gsd_watcher.rs
// serde(rename_all = "camelCase") — but all fields are single-word anyway.
// ---------------------------------------------------------------------------

/** Payload for `gsd-file-changed` events. */
export interface GsdFileChangedPayload {
  path: string;
  kind: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// Session state
// ---------------------------------------------------------------------------

/** Possible states of the GSD agent session. */
export type SessionState =
  | "idle"
  | "connecting"
  | "connected"
  | "streaming"
  | "disconnected"
  | "error";

